import type { Course, QuizQuestion, Exam } from '../types/curriculum';

// ── Helper: convert MVP quiz format to QuizQuestion[] ──────────

function q(id: string, question: string, options: string[], correctIndex: number, explanation?: string): QuizQuestion {
  return { id, question, options, correctIndex, explanation: explanation ?? '' };
}

function exam(id: string, title: string, passingScore: number, questions: QuizQuestion[], timeLimit?: number): Exam {
  return { id, title, passingScore, timeLimit, questions };
}

