// ── Helper for getting a course by ID ──────────────────────────
export function getCourseById(id: string): Course | undefined {
  return courses.find((c) => c.id === id);
}

// ── Helper for getting lesson IDs for a course ─────────────────
export function getCourseLessonIds(courseId: string): string[] {
  const course = getCourseById(courseId);
  return course ? course.lessons.map((l) => l.id) : [];
}

// ── Courses grouped by ECFL band (for ECFLOS.jsx) ───────────────
export const COURSES_BY_BAND: Record<string, Course[]> = courses.reduce((acc, c) => {
  const band = c.band || 'general';
  if (!acc[band]) acc[band] = [];
  acc[band].push(c);
  return acc;
}, {} as Record<string, Course[]>);
